Here are the key issues I see:

| # | Issue | Severity |
|---|-------|----------|
| 1 | **6 duplicate Gold/Silver tests** — identical logic, different data | High |
| 2 | **`TestTaxCalculation` packs 5 assertions** — one failure hides the rest | High |
| 3 | **`new DiscountService()` repeated 9×** — should be in the constructor | Medium |
| 4 | **Magic numbers** in shipping tests (`42, 7, 3`) — unclear intent | Medium |
| 5 | **Inconsistent naming** — `ShouldWork`, `TestTaxCalculation` vs `_Scenario_Expected` | Low |
| 6 | **Class not `sealed`** — MSTest best practice for perf | Low |

Here's the refactored version using `[DataRow]` and constructor init:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace DuplicateMagic.Tests;

[TestClass]
public sealed class DiscountServiceTests
{
    private readonly DiscountService _service;

    public DiscountServiceTests()
    {
        _service = new DiscountService();
    }

    [TestMethod]
    [DataRow(100.0, "Gold", 90.0, DisplayName = "Gold 10% off 100")]
    [DataRow(200.0, "Gold", 180.0, DisplayName = "Gold 10% off 200")]
    [DataRow(50.0, "Gold", 45.0, DisplayName = "Gold 10% off 50")]
    [DataRow(100.0, "Silver", 95.0, DisplayName = "Silver 5% off 100")]
    [DataRow(200.0, "Silver", 190.0, DisplayName = "Silver 5% off 200")]
    [DataRow(50.0, "Silver", 47.5, DisplayName = "Silver 5% off 50")]
    public void ApplyDiscount_ByTier_ReturnsDiscountedPrice(
        double price, string tier, double expected)
    {
        var result = _service.ApplyDiscount((decimal)price, tier);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(42, 7, 3, 882.0, DisplayName = "Standard weight")]
    [DataRow(150, 7, 3, 3150.0, DisplayName = "Heavy item")]
    public void CalculateShipping_ByWeight_ReturnsExpectedCost(
        int weight, int ratePerUnit, int zone, double expected)
    {
        var result = _service.CalculateShipping(weight, ratePerUnit, zone);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(100.0, 0.08, 108.0, DisplayName = "8% tax on 100")]
    [DataRow(200.0, 0.08, 216.0, DisplayName = "8% tax on 200")]
    [DataRow(100.0, 0.125, 112.5, DisplayName = "12.5% tax on 100")]
    [DataRow(200.0, 0.125, 225.0, DisplayName = "12.5% tax on 200")]
    [DataRow(100.0, 0.0, 100.0, DisplayName = "Zero tax")]
    public void ApplyTax_WithRate_ReturnsTaxedAmount(
        double amount, double taxRate, double expected)
    {
        var result = _service.ApplyTax((decimal)amount, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }
}
```

**What changed:**
- **11 methods → 3** using `[DataRow]` — each row runs as its own test with a clear `DisplayName`
- **Constructor** creates `_service` once (as `readonly`)
- **Class is `sealed`**
- **Consistent naming**: `Method_Scenario_Expected`
- `DataRow` uses `double` because it doesn't support `decimal` literals; the cast to `decimal` happens inside the method

> **Note:** The shipping test params (`42, 7, 3`) still look like magic numbers. If those represent something domain-specific (e.g., weight/rate/zone), consider naming them in the `DisplayName` or adding a comment—I guessed at parameter names above.
